code = """import json

# Get reviews from the query result
reviews = locals()['var_functions.query_db:4']

# Count reviews and calculate average rating per business
from collections import defaultdict

business_stats = defaultdict(list)
for review in reviews:
    business_ref = review['business_ref']
    rating = int(review['rating'])
    business_stats[business_ref].append(rating)

# Calculate average rating and count for each business
business_summary = []
for business_ref, ratings in business_stats.items():
    review_count = len(ratings)
    if review_count >= 5:  # Only businesses with at least 5 reviews
        avg_rating = sum(ratings) / review_count
        business_summary.append({
            'business_ref': business_ref,
            'review_count': review_count,
            'avg_rating': avg_rating
        })

# Sort by average rating descending
business_summary.sort(key=lambda x: x['avg_rating'], reverse=True)

# Get top business
top_business = business_summary[0] if business_summary else None

print('__RESULT__:')
print(json.dumps(top_business))"""

